555503,0.01012656,0.02144354,0.07174473,-0.01200112,-0.01101759,0.09014661,0.06875984,0.01081665,0.01303986,0.01273778,-0.02076205,0.01732644,-0.00672954,0.03067057,-0.04163497,-0.01070729,-0.06413202,-0.08939403,0.08381549,0.02788686,0.03985327,0.00254749,-0.02737117,-0.03300174,-0.06298575,-0.01345157,-0.00447480,-0.04537870,0.03219741,0.03122779,-0.02127664,0.04620612,0.00848718,0.03159278,0.01733819,-0.01837230,0.01340620,0.02914292,-0.05226180,0.07205520,0.01677897,0.03232237]',E'Quickstart\n\n```rust\nuse sqlx::postgres::PgPoolOptions;\n// use sqlx::mysql::MySqlPoolOptions;\n// etc.\n\n#[async_std::main] // Requires the `attributes` feature of `async-std`\n// or #[tokio::main]\n// or #[actix_web::main]\nasync fn main() -> Result<(), sqlx::Error> {\n    // Create a connection pool\n    //  for MySQL/MariaDB, use MySqlPoolOptions::new()\n    //  for SQLite, use SqlitePoolOptions::new()\n    //  etc.\n    let pool = PgPoolOptions::new()\n        .max_connections(5)\n        .connect("postgres://postgres:password@localhost/test").await?;\n\n    // Make a simple query to return the given parameter (use a question mark `?` instead of `$1` for MySQL/MariaDB)\n    let row: (i64,) = sqlx::query_as("SELECT $1")\n        .bind(150_i64)\n        .fetch_one(&pool).await?;\n\n    assert_eq!(row.0, 150);\n\n    Ok(())\n}\n```','{"source": "sqlx", "version": "0.8", "language": "rust", "title": "Cargo.toml", "section_title": "README", "url": "https://github.com/launchbadge/sqlx/blob/main/README.md", "topics": "sqlx,rust,sql,async,README", "categories": "database,sql,rust,async"}');
